async function copyUiLink(url, {
  promptMessage = 'лІБнБђл•Љ л≥µмВђнХШмДЄмЪФ.',
  shownNotice = 'лІБнБђл•Љ нСЬмЛЬнЦИмКµлЛИлЛ§.',
  successNotice = 'лІБнБђл•Љ л≥µмВђнЦИмКµлЛИлЛ§.',
  unavailableNotice = 'лЄМлЭЉмЪ∞м†Ак∞А лІБнБђ л≥µмВђл•Љ мІАмЫРнХШмІА мХКмКµлЛИлЛ§.',
} = {}) {
  try {
    if (!navigator.clipboard?.writeText) {
      throw new Error('clipboard-unavailable');
    }
    await navigator.clipboard.writeText(url);
    setUiNotice(successNotice);
    return { method: 'clipboard' };
  } catch {
    const prompted = showCopyPromptFallback(promptMessage, url);
    setUiNotice(prompted ? shownNotice : unavailableNotice);
    return { method: prompted ? 'prompt' : 'unavailable' };
  }
}

function showCopyPromptFallback(promptMessage, value) {
  if (typeof window.prompt !== 'function') {
    return false;
  }

  try {
    window.prompt(promptMessage, value);
    return true;
  } catch {
    return false;
  }
}

async function copyPlainTextValue(value, {
  promptMessage = 'к∞ТмЭД л≥µмВђнХШмДЄмЪФ.',
  shownNotice = 'к∞ТмЭД нСЬмЛЬнЦИмКµлЛИлЛ§.',
  successNotice = 'к∞ТмЭД л≥µмВђнЦИмКµлЛИлЛ§.',
  unavailableNotice = 'лЄМлЭЉмЪ∞м†Ак∞А нЕНмК§нКЄ л≥µмВђл•Љ мІАмЫРнХШмІА мХКмКµлЛИлЛ§.',
} = {}) {
  const normalizedValue = String(value || '').trim();
  if (!normalizedValue) {
    setUiNotice('л≥µмВђнХ† к∞ТмЭі мЧЖмКµлЛИлЛ§.');
    return;
  }
  try {
    if (!navigator.clipboard?.writeText) {
      throw new Error('clipboard-unavailable');
    }
    await navigator.clipboard.writeText(normalizedValue);
    setUiNotice(successNotice);
    return { method: 'clipboard' };
  } catch {
    const prompted = showCopyPromptFallback(promptMessage, normalizedValue);
    setUiNotice(prompted ? shownNotice : unavailableNotice);
    return { method: prompted ? 'prompt' : 'unavailable' };
  }
}

